const body = $input.first().json.body;
const data = body?.data;
if (!data) return [];
const phone = (data.key?.remoteJid || '').replace('@s.whatsapp.net','').replace('@c.us','');
const text = data.message?.conversation || data.message?.extendedTextMessage?.text || '';
const fromMe = data.key?.fromMe || false;
if (fromMe || !phone || !text) return [];
return [{ json: { phone, text, instance: body.instance || 'cs-ai-demo 2' } }];

const text = $('Extract Message').item.json.text.trim();
const map = {'1':'beauty','2':'exchange','3':'insurance','4':'realestate','5':'shop'};
const business = map[text] || 'beauty';
const phone = $('Extract Message').item.json.phone;
return [{ json: { phone, business_type: business } }];

const loadData = $('Load Prompt').item.json;
const historyRaw = $input.first().json;

const history = historyRaw?.history || [];

const messages = [
  { role: 'system', content: loadData.systemPrompt }
];

for (const h of history) {
  if (h.role && h.content) {
    messages.push({ role: h.role, content: h.content });
  }
}

messages.push({ role: 'user', content: loadData.userText });

return [{ json: {
  messages,
  phone: loadData.phone,
  business: loadData.business,
  userText: loadData.userText
}}];

const aiResp = $input.first().json;
const content = aiResp.choices?.[0]?.message?.content || '';
const phone = $('Build Messages').item.json.phone;
const business = $('Build Messages').item.json.business;
const userText = $('Build Messages').item.json.userText;

const intentMatch = content.match(/\[INTENT:([A-Z_]+)\]/);
const intent = intentMatch ? intentMatch[1] : 'OTHER';

const quoteMatch = content.match(/\[QUOTE:({[\s\S]*?})\]/);
let quoteData = {};
if (quoteMatch) {
  try { quoteData = JSON.parse(quoteMatch[1]); } catch(e) {}
}

const replyText = content
  .replace(/\[QUOTE:{[\s\S]*?}\]/g, '')
  .replace(/\[INTENT:[A-Z_]+\]/g, '')
  .trim();

return [{ json: { phone, business, intent, replyText, quoteData, userText } }];
